// Proposed:
// lib/core/error/cognito_exception_mapper.dart
class CognitoExceptionMapper {
  static const Map<String, AuthException> _errorMap = {
    'UserNotFoundException': AuthException('No account found...', code: 'USER_NOT_FOUND'),
    'NotAuthorizedException': AuthException('Incorrect email...', code: 'INVALID_CREDENTIALS'),
  };

  static AuthException fromException(Exception e) {
    final code = _extractErrorCode(e);
    return _errorMap[code] ?? AuthException('Authentication failed', code: 'UNKNOWN');
  }
}

